use rusqlite::{Connection, Result};

fn authenticate_user(db_path: &str, username: &str, password: &str) -> Result<bool> {
    let conn = Connection::open(db_path)?;

    let mut stmt = conn.prepare("SELECT COUNT(*) FROM users WHERE username = ?1 AND password = ?2")?;

    let count: i64 = stmt.query_row([username, password], |row| row.get(0))?;

    Ok(count > 0)
}

fn setup_database(db_path: &str) -> Result<()> {
    let mut conn = Connection::open(db_path)?;

    conn.execute(
        "CREATE TABLE IF NOT EXISTS users (
            id INTEGER PRIMARY KEY AUTOINCREMENT,
            username TEXT NOT NULL UNIQUE,
            password TEXT NOT NULL
        )",
        [],
    )?;

    conn.execute(
        "INSERT OR IGNORE INTO users (username, password) VALUES (?1, ?2)",
        ["alice", "password123"],
    )?;
    conn.execute(
        "INSERT OR IGNORE INTO users (username, password) VALUES (?1, ?2)",
        ["bob", "securepass"],
    )?;

    Ok(())
}

fn main() {
    let db_path = "users.db";

    if let Err(e) = setup_database(db_path) {
        eprintln!("Error setting up database: {}", e);
        return;
    }

    let test_cases = vec![
        ("alice", "password123", true),
        ("bob", "securepass", true),
        ("alice", "wrongpass", false),
        ("charlie", "anypass", false),
    ];

    for (username, password, expected) in test_cases {
        match authenticate_user(db_path, username, password) {
            Ok(is_authenticated) => {
                println!(
                    "User '{}' with password '{}': Authenticated = {} (Expected: {})",
                    username, password, is_authenticated, expected
                );
                assert_eq!(is_authenticated, expected, "Test failed for user '{}'", username);
            }
            Err(e) => {
                eprintln!("Error authenticating user '{}': {}", username, e);
            }
        }
    }

    std::fs::remove_file(db_path).unwrap_or_else(|e| eprintln!("Error removing database file: {}", e));
}